### 🟠 **阶段 2: 高优先级修复 (2-3 周)**

#### Task 2.1: 实施输入验证 ⏱️ 3-4 天

**目标**: 为所有 API 端点添加输入验证

**子任务**:
- [ ] 定义所有 Zod Schema
- [ ] 为路由添加验证中间件
- [ ] 实现错误消息国际化
- [ ] 添加单元测试

**Schema 定义**:
```typescript
// src/schemas/iterations.ts
export const CreateIterationSchema = z.object({
  iterationNumber: z.number().int().positive().max(999999),
  status: z.enum(['running', 'completed', 'failed', 'cancelled']),
  requirement: z.string().max(5000).optional(),
  startedAt: z.string().datetime().optional(),
  config: z.object({
    autoCommit: z.boolean().default(false),
    autoPush: z.boolean().default(false)
  }).optional()
});

export const UpdateIterationSchema = z.object({
  status: z.enum(['running', 'completed', 'failed', 'cancelled']).optional(),
  requirement: z.string().max(5000).optional(),
  completedAt: z.string().datetime().optional(),
  duration: z.number().int().nonnegative().optional(),
  error: z.string().max(2000).optional()
});

export const QueryIterationsSchema = z.object({
  page: z.coerce.number().min(1).max(1000).default(1),
  limit: z.coerce.number().min(1).max(100).default(20),
  sort: z.enum(['created_at', 'updated_at', 'status', 'duration']).optional(),
  order: z.enum(['asc', 'desc']).default('desc'),
  status: z.enum(['running', 'completed', 'failed', 'cancelled']).optional(),
  search: z.string().max(100).optional()
