#### Task 2.2: WebSocket 安全加固 ⏱️ 2-3 天

**目标**: 增强 WebSocket 连接安全性

**子任务**:
- [ ] 实现连接认证
- [ ] 添加消息频率限制
- [ ] 实现消息大小限制
- [ ] 添加异常处理
- [ ] 实现连接监控

**代码实现**:
```typescript
// src/websocket/security.ts
import { FastifyRequest } from 'fastify';
import { SocketStream } from '@fastify/websocket';
import { verifyToken } from '../auth/auth.service';

interface WebSocketClient {
  socket: any;
  userId: number;
  role: string;
  messageCount: number;
  lastMessageTime: number;
}

const clients = new Map<any, WebSocketClient>();
const RATE_LIMIT = 60; // 每分钟60条消息

export async function authenticateWebSocket(
  connection: SocketStream,
  request: FastifyRequest
): Promise<boolean> {
  try {
    const token = request.headers.authorization?.replace('Bearer ', '');

    if (!token) {
      connection.socket.close(4001, 'Missing token');
      return false;
    }

    const decoded = verifyToken(token);

    const client: WebSocketClient = {
      socket: connection.socket,
      userId: decoded.userId,
      role: decoded.role,
      messageCount: 0,
      lastMessageTime: Date.now()
    };

    clients.set(connection.socket, client);

    // 启动频率限制重置
    setInterval(() => {
      client.messageCount = 0;
    }, 60000);

    return true;
  } catch (error) {
    connection.socket.close(4001, 'Invalid token');
    return false;
  }
}

export function checkRateLimit(socket: any): boolean {
  const client = clients.get(socket);

  if (!client) return false;

  const now = Date.now();
  const elapsed = now - client.lastMessageTime;

  // 重置计数器（如果超过1分钟）
  if (elapsed > 60000) {
    client.messageCount = 0;
    client.lastMessageTime = now;
  }

  // 检查频率限制
  if (client.messageCount >= RATE_LIMIT) {
    socket.close(4008, 'Rate limit exceeded');
    return false;
  }

  client.messageCount++;
  client.lastMessageTime = now;
  return true;
}

export function getClientInfo(socket: any): WebSocketClient | undefined {
  return clients.get(socket);
}

export function removeClient(socket: any) {
  clients.delete(socket);
}
```

