  // API 配置
  API_TIMEOUT_MS: z.coerce.number().min(1000).max(300000).default(30000),
  MAX_REQUEST_SIZE: z.coerce.number().default(1024 * 1024), // 1MB

  // 速率限制
  RATE_LIMIT_MAX: z.coerce.number().min(1).default(100),
  RATE_LIMIT_WINDOW: z.string().default('1 minute'),

  // 日志配置
  LOG_LEVEL: z.enum(['fatal', 'error', 'warn', 'info', 'debug', 'trace']).default('info'),

  // 安全配置
  ENABLE_SECURITY_HEADERS: z.coerce.boolean().default(true),
  ENABLE_CSP: z.coerce.boolean().default(true),
  ENABLE_HSTS: z.coerce.boolean().default(true),

  // Agent 配置
  PERMISSION_MODE: z.enum(['default', 'acceptEdits', 'bypassPermissions', 'dontAsk']).default('default'),
  ALLOWED_PATHS: z.string().optional(),
  BLOCKED_PATHS: z.string().default('.env,.git,node_modules,dist')
});

export function validateEnv() {
  try {
    const validated = EnvSchema.parse(process.env);
    return validated;
  } catch (error) {
    if (error instanceof z.ZodError) {
      console.error('❌ Invalid environment configuration:');
      error.errors.forEach(err => {
        console.error(`  - ${err.path.join('.')}: ${err.message}`);
      });
      process.exit(1);
    }
    throw error;
  }
}

// 在应用启动时调用
const env = validateEnv();
